import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as n,a as s}from"./app-23442423.js";const t="/assets/images/vasvari/InputEvents.webp",l="/assets/images/vasvari/EventFiltersFiring.webp",o="/assets/images/vasvari/MouseEventJavaFXv2.webp",i={},d=s('<h1 id="events" tabindex="-1"><a class="header-anchor" href="#events" aria-hidden="true">#</a> Events</h1><p>A <strong>JavaFX</strong> felhasználói felületei szinte teljesen eseményvezéreltek. A legtöbb ember ismeri a műveleti eseményeket, a billentyű- és egéreseményeket, de a felhasználói felület szinte minden összetett frissítése valamilyen esemény segítségével történik. És mégis, az események a <strong>JavaFX</strong> egyik legkevésbé kihangsúlyozott része.</p><h2 id="a-javafx-esemenyek-utmutatoja" tabindex="-1"><a class="header-anchor" href="#a-javafx-esemenyek-utmutatoja" aria-hidden="true">#</a> A JavaFX események útmutatója</h2><p>Általános szabályként elmondható, hogy ha egyszerű érték alapú változtatást kell végrehajtani, akkor ezt Property kötéssel lehet elérni. Minden egyéb esetben érdemes eseményeket használni. Az események sokoldalúak és stabil módot biztosítanak a változások vezérlésére az alkalmazásban.</p><p>Eseménynek számít bármely állapotváltozás egy bemeneti eszközön (<em>például egér vagy érintőképernyő</em>), egy felhasználói művelet (<code>ActionEvent</code>) vagy egy háttérfeladat során. Az események összetett csomópontok, például <code>TableView</code>-ben és <code>ListView</code>-ben történő görgetés vagy szerkesztés eredményeként is kiválthatunk.</p><p>Nagyon alapszinten az <code>Event</code> objektum egy osztály, meglepően kevés paraméterrel. Nem tartalmaz semmilyen futtatható kódot, és nem is futtat semmilyen kódot. Ez egy jelzés a rendszernek, hogy valami megváltozott.</p><p>A JavaFX jelentős támogatást nyújt a végrehajtható kódok futtatásához, amelyeket külön az <code>EventHandler</code> osztályon keresztül definiálnak, minden állapotváltozás esetén.A JavaFX <em>90</em> különálló eseménytípust támogat, és lehetőség van az <code>Event</code> osztály kiterjesztésére és további egyéni funkciók definiálására.</p><h3 id="hogyan-mukodnek-az-esemenyek" tabindex="-1"><a class="header-anchor" href="#hogyan-mukodnek-az-esemenyek" aria-hidden="true">#</a> Hogyan működnek az események?</h3><p>Nem hazudok, ha azt mondom, hogy egy <code>Event</code> rendkívül egyszerű. Ami bonyolult, az a háttérben futó folyamatok, amelyek megvalósítják az eseménykezelő rendszert. Ebben a szakaszban áttekintjük, mi határozza meg egy <code>Event</code>-et, és hogyan állíthatjuk be a kódunkat, hogy minden alkalommal végrehajtsa, amikor egy bizonyos eseményt észlel.</p><h2 id="az-event-osztaly" tabindex="-1"><a class="header-anchor" href="#az-event-osztaly" aria-hidden="true">#</a> Az Event osztály</h2><p>A JavaFX-ben egy Eseménynek négy tulajdonsága van:</p><ul><li>Forrás (<code>Source</code>)</li><li>Cél (<code>Target</code>)</li><li>Típus (<code>Type</code>)</li><li>Felhasználva (<code>consumed</code>)</li></ul><div class="hint-container info"><p class="hint-container-title">A consumed (felhasználva) nevű logikai paramétert általában figyelmen kívül hagyják, de valójában fontos az alkalmazás viselkedése szempontjából. Nézzük meg mindegyiket sorban.</p></div><h3 id="source" tabindex="-1"><a class="header-anchor" href="#source" aria-hidden="true">#</a> Source</h3><p>JavaFX a <code>Node</code>-ot rendeli hozzá az esemény forrásaként a létrehozásnál, ami az esemény okának megfelelően van meghatározva. (<em>egér, billentyű, művelet stb.</em>).</p><p>A Java natívan támogatja az eseményeket az <code>EventObject</code> osztállyal. Még mielőtt a <strong>JavaFX</strong> a saját Target és <code>Type</code> attribútumait is rárakná, az esemény alapvető része a forrás. A <code>Target</code>, a <code>Type</code> és a <code>Consumed</code> a <strong>JavaFX</strong> által bevezetett konstrukciók, de minden eseményt valaminek okoznia kell. Ez a forrás.</p><p>Az eseményforrás az az objektum, amely az eseményt okozza. Sokféle állapotváltozás okozhat eseményt:</p><ul><li>Az egér mozgása, kattintás, húzás</li><li>gesztusok, érintőképernyő bevitele, nagyítás.</li><li>Egy gomb aktiválása</li><li>Egy feladat elindulása, befejezése vagy állapotváltozása.</li></ul><p>Még akkor is, ha egy bemeneti eszközről van szó, amelynek állapota megváltozott, a <strong>JavaFX</strong> hozzárendeli a saját forrását, amely gyakran egy csomópont.</p><p>E rugalmasság érdekében az esemény forrása <code>Object</code>-ként tárolódik, és a <code>getSource()</code> metóduson keresztül érhető el.</p><p>Az esemény céljától eltérően, bizonyos speciális esetekben az esemény forrása változhat az esemény végrehajtása során. Az <strong>Eseménytípusok</strong> című fejezetben beszélek arról, hogyan működhet ez.</p><p>???????????????</p><p>????????</p><h3 id="target" tabindex="-1"><a class="header-anchor" href="#target" aria-hidden="true">#</a> Target</h3><p>A <strong>JavaFX</strong> kiterjeszti a <code>java.util</code> fájlban szereplő <code>EventObject</code>-et, hogy további paramétereket adjon hozzá. Ezek közül az első a <code>target</code>, amely azt a <code>Node</code>-ot határozza meg, amelyre az esemény hatott. Például, amikor egy <code>TextField</code> mezőbe gépelünk, minden billentyűleütés <code>KeyEvent</code>-ként regisztrálódik, és minden ilyen esemény célpontja a <code>TextField</code> mező lesz.</p><figure><img src="'+t+`" alt="A JavaFX kiterjeszti a Java  osztályt a specifikus eseménytípusok és az  paraméter hozzáadásához." tabindex="0" loading="lazy"><figcaption>A JavaFX kiterjeszti a Java <code>EventObject</code> osztályt a specifikus eseménytípusok és az <code>EventTarget</code> paraméter hozzáadásához.</figcaption></figure><p>Az <code>EventObject</code> kiterjesztése rugalmasságot biztosít a <strong>JavaFX</strong> számára az esemény céljának <strong>JavaFX</strong>-specifikus módon történő tárolásához és megadásához. Ebben az esetben a <strong>JavaFX</strong>-ben bármely esemény céljának implementálnia kell az <code>EventType</code> interfészt. Ez az interfész egyetlen metódust tartalmaz, amely paraméterként egy <code>EventDispatchChain</code>-t fogad, és egy <code>EventDispatchChain</code>-t ad vissza.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token class-name">EventDispatchChain</span> <span class="token function">buildEventDispatchChain</span><span class="token punctuation">(</span><span class="token class-name">EventDispatchChain</span> tail<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Ez áll a <strong>JavaFX</strong> eseménykezelési módjának középpontjában. Rengeteg <strong>JavaFX</strong> objektum bővíti az <code>EventTarget</code> interfészt:</p><ul><li><strong>Nodes, Panes and Controls</strong> <i class="fa-solid fa-window-maximize"></i></li><li><strong>Transforms</strong> <i class="fa-solid fa-rotate"></i></li><li><strong>Charts</strong> <i class="fa-solid fa-chart-line"></i></li><li><strong>Lights and Cameras</strong> <i class="fa-solid fa-lightbulb"></i></li><li><strong>Mesh data</strong> <i class="fa-solid fa-layer-group"></i></li><li><strong>Shapes</strong> <i class="fa-solid fa-shapes"></i></li><li><strong>Skins</strong> <i class="fa-regular fa-file-code"></i></li></ul><p>Ez lehetővé teszi a <strong>JavaFX</strong> számára, hogy a felhasználói felület bármely elemén eseményeket indítson, de nekünk, fejlesztőknek is lehetővé teszi, hogy ezeket az eseményeket indítsuk.</p><p>Mivel az eseményeket a <strong>JavaFX</strong> így kezeli, azt is biztosítja, hogy az általunk megadott végrehajtható kódot az <code>Application</code> szálon küldjük el. Ez egy hihetetlenül stabil módja az olyan összetett elemek, mint a diagramok és a vizuálisan bonyolult vezérlők frissítésének.</p><h3 id="type" tabindex="-1"><a class="header-anchor" href="#type" aria-hidden="true">#</a> Type</h3><p>A JavaFX az eseménytípust az esemény eredete (<em>egér, billentyű, művelet stb.</em>) és az állapotváltozás jellege (<em>billentyű elengedése, egérkattintás, feladat elindítása stb.</em>) alapján jelöli ki.</p><p>Az eseménytípusok az <code>EventType</code> osztály által meghatározott <strong>JavaFX</strong>-specifikus paraméterek. Tudomásom szerint a JavaFX két okból definiálja az eseménytípusokat az <code>EventType</code> osztály segítségével:</p><h4 id="tipusbiztonsag" tabindex="-1"><a class="header-anchor" href="#tipusbiztonsag" aria-hidden="true">#</a> Típusbiztonság</h4><p>Egy <code>EventType</code> meghatározásakor meg kell adnia az eseményt, amelyre a típust definiálja, és meg kell adnia az esemény nevét. A <strong>JavaFX</strong> <code>90</code> előre definiált eseménytípussal rendelkezik, amelyek az <code>Event</code> és az <code>al-Event</code> osztályok statikus tagváltozóiként érhetők el.</p><h4 id="kulonbseg-az-awt-tol" tabindex="-1"><a class="header-anchor" href="#kulonbseg-az-awt-tol" aria-hidden="true">#</a> Különbség az AWT-től</h4><p>A <strong>Java</strong> másik ablakkezelő megoldása az absztrakt ablakkezelő eszközkészlet (<code>AWT</code>). Az események típusbiztonságát ebben az eszközkészletben úgy érték el, hogy az eseményeket egész számokként adták meg.</p><p>Ez nem tökéletes típusbiztonság, de statikus tagváltozóként lettek definiálva, mint például <code>MOUSE_CLICKED = 500</code>, így legalább könnyen lehetett rájuk hivatkozni.</p><p>Ha a <strong>JavaFX</strong> is ezt tette volna, a <code>MouseEvent.MOUSE_CLICKED</code> (<code>AWT import</code>) és a <code>MouseEvent.MOUSE_CLICKED</code> (<code>JavaFX import</code>) elég nehezen lenne észrevehető. Ha a statikus változók mögötti számok különbözőek lennének, talán észre sem vennéd, amíg a kódod össze nem omlik, és kézzel kell hibátkeresned.</p><h3 id="consumed" tabindex="-1"><a class="header-anchor" href="#consumed" aria-hidden="true">#</a> consumed</h3><p>Bármelyik ponton ebben a folyamatban, beleértve azt is, mielőtt az esemény elérte volna a célját, az eseményt kezelni lehet, és a folyamat azonnal leáll.</p><p>Nem lehet eléggé hangsúlyozni, milyen hasznos ez az események vezérlésében egy teljes jelenet során, és milyen gyakran fogod használni az eseményvezérelt fejlesztés során.</p><p>A <strong>JavaFX</strong> eseménykezelésének alapvető része, hogy az események a jelenetgrafikonon áthaladnak. Egy levélcsomóponton bekövetkező esemény az adott típusú eseményeket a tetején lévő Windowtól lefelé a csomópontig, majd vissza felfelé indítja el.</p><p>Ha egy eseményt a diszpécserlánc végrehajtásának egy részénél fogyasztanak el, akkor az azonnal leáll, és további események nem lőnek ki.</p><p>Lehetőség van egy esemény leállítására, mielőtt az elérné a célcsomópontot. Ez az eseményszűrők gyakori felhasználási módja.</p><p>Az eseményeket a <code>consume()</code> metódussal lehet felhasználni. Az <code>isConsumed()</code> metódus meghívásával állapítható meg, hogy egy eseményt felhasználtak-e már.</p><h2 id="esemenykivaltodasi-fazisok" tabindex="-1"><a class="header-anchor" href="#esemenykivaltodasi-fazisok" aria-hidden="true">#</a> Eseménykiváltódási fázisok</h2><p>Amikor egy esemény kiváltódik a <strong>JavaFX</strong>-ben, az a jelenettől (<code>scene</code>) a csomópontig (<code>node</code>), majd a csomóponttól vissza a jelenetig utazik.</p><p>Ehhez három dologra van szükség:</p><ol><li>Tudni, hogy az eseménynek melyik csomópontba kell eljutnia.</li><li>Azonosítani a <code>Window</code>-ot, többablakos alkalmazásokban.</li><li>Tudni, milyen útvonalon kell végigmennie a jelenet és a csomópont között.</li></ol><p>Ezek a lépések az esemény kiváltásában. Az első lépést <strong>Target Selection</strong> (<em>Célcsoport kiválasztásnak</em>) nevezik. A második és harmadik lépést együtt hajtják végre egy folyamatban, amit <strong>Route Construction</strong> (<em>Útvonal építésnek</em>) neveznek.</p><p>Ezek mindegyikén végigmegyünk, majd befejezésül végigmegyünk az események indításának módján.</p><h3 id="cel-kivalasztasa" tabindex="-1"><a class="header-anchor" href="#cel-kivalasztasa" aria-hidden="true">#</a> Cél kiválasztása</h3><p>A JavaFX a bekövetkezett esemény típusa és az eseményt létrehozó bemeneti eszköz alapján választja ki az esemény célpontját.</p><p>Mivel a célpont kiválasztása típusfüggő, az alábbi legördülő listákban részletesebben áttekinthetjük az egyes eseménytípusok célpont-kiválasztását.</p><h3 id="utvonal-epites" tabindex="-1"><a class="header-anchor" href="#utvonal-epites" aria-hidden="true">#</a> Útvonal építés</h3><p>Új események esetén - azoknál az eseményeknél, ahol a cél egy csomópont a jelenetben - a cél csomópont létrehoz egy útvonalat önmaga és az <code>Window</code> között.</p><p>A logika valami ilyesmit követ:</p><ul><li>Szerezd be az összes csomópontot innen a <code>Scene</code>:</li><li>A célcsomópont hozzáadása az útvonalhoz végpontként.</li><li>Ha a célnak van szülője, fűzzük hozzá a szülőcsomópontot az útvonalhoz.</li><li>Folytassuk a szülők hozzáadását, amíg el nem érek egy olyan csomóponthoz, amelynek nincs szülője.</li><li>Ez a gyökércsomópont.</li><li>Használjuk a gyökércsomópontot a <code>Scene</code> megszerzéséhez.</li></ul><p>Ezután visszaadjuk az útvonalat, amelyet az eredeti <code>buildEventDispatchChain()</code> hívás során hoztunk létre a <code>Target node</code>-on.<br> Az útvonalkészítés után az események készen állnak arra, hogy a <code>dispatch chain</code> minden láncszeméről elküldhetők legyenek.</p><h3 id="esemeny-rogzitese" tabindex="-1"><a class="header-anchor" href="#esemeny-rogzitese" aria-hidden="true">#</a> Esemény rögzítése</h3><p>A folyamat most az események lánca, ahol az esemény a lánc első elemenél kezdődik, majd fokozatosan halad végig minden csomóponton, mígnem elérjük a csomópontját.</p><p>Itt válik fontossá az esemény szűrők és az eseménykezelők közötti különbség. Ha még nem hallottál az esemény szűrőkről, azokat hozzá lehet adni bármely <code>EventTargethez</code> (csomópontok, jelenet, diagramok, feladatok stb.) az <code>addEventFilter()</code>-t.</p><p>Az esemény szűrők remekül használhatók a gyermek <code>node</code>-ok viselkedésének irányítására, mivel a <code>SceneGraph</code> bejárása során a szülők először hajtják végre azokat.</p><div class="hint-container info"><p class="hint-container-title">Egy csomópontnak rendelkeznie kell a megfelelő típusú esemény szűrővel ahhoz, hogy az adott szűrő működjön.</p></div><figure><img src="`+l+`" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>Eseményszűrők bármely <code>EventTargethez</code> (csomópontokhoz, feladatokhoz és szolgáltatásokhoz) hozzáadhatók az <code>addEventFilter()</code> meghívásával a megfelelő <code>EventType</code> és <code>EventHandler</code> megadásával.</p><div class="hint-container info"><p class="hint-container-title">Event Bubbling</p><p>Például, ha egy gombra kattintasz, az esemény először a gombon lévő eseménykezelőkön keresztül fut át, majd továbbhalad a gomb szülőelemei felé (pl. a gomb tartalmazó panel vagy ablak). Egyes eseménykezelők csak a cél elemen futnak le, mások viszont tovább is terjednek a szülők felé.</p><p>Ez a mechanizmus lehetővé teszi az eseménykezelők hierarchiáját és a felfelé irányuló eseményáramlást, ami rugalmasságot biztosít az események kezelésében a felhasználói felületek fejlesztése során.</p></div><h3 id="event-bubbling" tabindex="-1"><a class="header-anchor" href="#event-bubbling" aria-hidden="true">#</a> Event Bubbling</h3><p>Azok az események, amelyeket a célokon regisztráltak, a cél felől az ablak felé haladva kerülnek végrehajtásra, növekvő sorrendben.</p><p>Megjegyzés: Ahhoz, hogy az adott kezelő működjön, a csomópontnak rendelkeznie kell a megfelelő típusú eseménykezelővel.</p><p>Eseménykezelőket hasonló módon lehet hozzáadni, mint esemény szűrőket, de ehhez az <code>addEventHandler()</code> módszert kell használni.</p><p>Tekintsük meg, hogyan lehet definiálni az eseményszűrőket és eseménykezelőket.</p><h2 id="futtathato-kod-definialasa-egy-eventhandler-ben" tabindex="-1"><a class="header-anchor" href="#futtathato-kod-definialasa-egy-eventhandler-ben" aria-hidden="true">#</a> Futtatható kód definiálása egy <code>EventHandler</code>-ben</h2><p>Amikor egy eseményre adott választ szeretnénk definiálni, akkor egy EventHandler objektumot kell használnunk. A neve ellenére ugyanazt az objektumot használjuk mind az eseményszűrőkhöz, mind az eseménykezelőkhöz.</p><h3 id="eventhandler-letrehozasa" tabindex="-1"><a class="header-anchor" href="#eventhandler-letrehozasa" aria-hidden="true">#</a> EventHandler létrehozása</h3><p>Ezt úgy tehetjük meg, hogy az <code>EventHandler</code>-t névtelen belső osztályként vagy <code>lambda</code>-kifejezésként definiáljuk.</p><h3 id="eventhandler-definialasa" tabindex="-1"><a class="header-anchor" href="#eventhandler-definialasa" aria-hidden="true">#</a> EventHandler definiálása</h3><p>Az <code>EventHandler</code> objektum egy objektum egyetlen metódussal, amelyet felül kell írnunk, amikor példányosítjuk. Mivel az <code>EventHandler</code> interfész paraméterezett, meg kell adnunk, hogy milyen típusú eseményt kezelünk. Ebben az esetben egy <code>MouseEventet</code> fogunk használni.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token class-name">EventHandler</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">MouseEvent</span><span class="token punctuation">&gt;</span></span> eventHandler <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">EventHandler</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token punctuation">&gt;</span></span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token annotation punctuation">@Override</span>
    <span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">handle</span><span class="token punctuation">(</span><span class="token class-name">MouseEvent</span> event<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token comment">//executable code</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="az-esemenykezelo-definiciojanak-csereje-egy-lambda-kifejezessel" tabindex="-1"><a class="header-anchor" href="#az-esemenykezelo-definiciojanak-csereje-egy-lambda-kifejezessel" aria-hidden="true">#</a> Az eseménykezelő definíciójának cseréje egy lambda kifejezéssel</h3><p>Az <code>EventHandler</code> egy funkcionális interfész (egy interfész egyetlen metódussal). A kényelem érdekében az <code>EventHandler</code> interfész <code>handle()</code> metódusa egy lambda kifejezéssel is megadható.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token class-name">EventHandler</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">MouseEvent</span><span class="token punctuation">&gt;</span></span> eventHandler <span class="token operator">=</span> event <span class="token operator">-&gt;</span> <span class="token punctuation">{</span>
    <span class="token comment">//executable code</span>
<span class="token punctuation">}</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="esemenyszurok-esemenykezelok-hozzaadasa-es-eltavolitasa" tabindex="-1"><a class="header-anchor" href="#esemenyszurok-esemenykezelok-hozzaadasa-es-eltavolitasa" aria-hidden="true">#</a> Eseményszűrők, eseménykezelők hozzáadása és eltávolítása</h3><p>Amikor eseménykezelőt definiálunk és adunk hozzá egy csomóponthoz (vagy feladathoz), meghatározzuk, hogy az adott eseménynek milyen típusától szeretnénk, ha a kódunk kiváltódna. Például, ha azt szeretnénk, hogy a kódunk a jelenetünk gyökércsomópontjának bármely egéreseményétől elinduljon, használhatjuk a <code>MouseEvent.ANY</code> eseménytípust.</p><p>Ha egy eseménykezelőt a kód egy későbbi pontján majd el akarunk távolítani, akkor meg kell tartanunk a létrehozott <code>EventHandler</code> objektumra való hivatkozást.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token comment">//define the handler</span>
<span class="token class-name">EventHandler</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">MouseEvent</span><span class="token punctuation">&gt;</span></span> eventHandler <span class="token operator">=</span> event <span class="token operator">-&gt;</span> <span class="token punctuation">{</span>
    <span class="token comment">//executable code</span>
<span class="token punctuation">}</span><span class="token punctuation">;</span>
<span class="token comment">//add the handler</span>
rootNode<span class="token punctuation">.</span><span class="token function">addEventHandler</span><span class="token punctuation">(</span>
        <span class="token class-name">MouseEvent</span><span class="token punctuation">.</span><span class="token constant">ANY</span><span class="token punctuation">,</span> <span class="token comment">//specify the type of event to listen for</span>
        eventHandler<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token comment">//later remove the handler</span>
rootNode<span class="token punctuation">.</span><span class="token function">removeEventHandler</span><span class="token punctuation">(</span>
        <span class="token class-name">MouseEvent</span><span class="token punctuation">.</span><span class="token constant">ANY</span><span class="token punctuation">,</span> <span class="token comment">//this should be the same as defined above</span>
        eventHandler<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Ugyanilyen egyszerű az eseményszűrők definiálása és eltávolítása az <code>addEventFilter()</code> és <code>removeEventFilter()</code> metódusok segítségével.</p><p>Néhány egyszerű dolgot azonban nem szabad elfelejteni:</p><ul><li>Ha egy eseménykezelőt adtál hozzá, akkor egy eseménykezelőt kell eltávolítanod (nem pedig egy szűrőt), és fordítva.</li><li>Az esemény típusának ugyanaznak kell lennie, amikor eltávolítod, mint amikor hozzáadod.</li></ul><h3 id="kenyelmi-metodusok-hasznalata" tabindex="-1"><a class="header-anchor" href="#kenyelmi-metodusok-hasznalata" aria-hidden="true">#</a> Kényelmi metódusok használata</h3><p>Néha célszerű kényelmi módszereket használni, például a <code>setOnMousePressed()</code> módszert eseménykezelők meghatározásához. Az eseménykezelők szintaxisa:</p><p><code>setOn</code> <code>EventType</code> <code>()</code></p><p>Íme néhány példa:</p><ul><li>setOnMousePressed() (csomópontok - nodes)</li><li>setOnKeyReleased() (csomópontok - nodes)</li><li>setOnTaskRunning() (feladatok - tasks)</li><li>setOnScrollFinished() (csomópontok virtuális folyammal - nodes with virtual flow)</li></ul><p>A kényelmi módszerek azért hasznosak, mert ugyanannak a módszernek a meghívásával és egy null hivatkozás átadásával eltávolíthatja a kezelőt anélkül, hogy emlékeznie kellene a hivatkozásra:</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token function">setOnMousePressed</span><span class="token punctuation">(</span><span class="token keyword">null</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Ezen eseménykezelők biztosan akkor kerülnek végrehajtásra, miután az adott csomóponton lévő ugyanolyan típusú bármely más eseménykezelő lefutott.</p><h2 id="esemenytipusok" tabindex="-1"><a class="header-anchor" href="#esemenytipusok" aria-hidden="true">#</a> Eseménytípusok</h2><p>Az események általában bemeneti eseményekre és JavaFX-specifikus eseményekre oszthatók. Az <code>ActionEvents</code> bemenetet igényelnek, de a bemeneti típusokat is átfogják, és a <strong>JavaFX</strong> belsőleg hozza létre őket, ezért ezeket nem a bemeneti, hanem a JavaFX-specifikus események közé soroljuk.</p><h3 id="az-operacios-rendszer-altal-generalt-bemeneti-esemenyek" tabindex="-1"><a class="header-anchor" href="#az-operacios-rendszer-altal-generalt-bemeneti-esemenyek" aria-hidden="true">#</a> Az operációs rendszer által generált (bemeneti) események</h3><p>A bemeneti események, például az egér-, billentyűzet- és gesztusesemények az alkalmazás szintje felett történnek, és az operációs rendszer továbbítja őket az alkalmazásunknak. A <strong>JavaFX</strong> háttérfolyamatai ezeket az információkat arra használják, hogy azonosítsák a megfelelő csomópontot, amelyen az eseményt végrehajtják.</p><figure><img src="`+o+`" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h3 id="billentyuesemenyek" tabindex="-1"><a class="header-anchor" href="#billentyuesemenyek" aria-hidden="true">#</a> Billentyűesemények</h3><p>A billentyűeseményeket az operációs rendszer generálja, amikor egy billentyű állapotát megváltoztatja - vagyis, lenyomják vagy felengedik. Ha egy billentyű hosszú ideig lenyomva marad, az operációs rendszer további billentyűeseményeket kezdeményezhet.</p><h3 id="egeresemenyek" tabindex="-1"><a class="header-anchor" href="#egeresemenyek" aria-hidden="true">#</a> Egeresemények</h3><p>A <code>MouseEvent</code> osztály meghatározza az egérkurzor pozíciójának vagy gombállapotainak bármilyen változását. Ahogyan a billentyűesemények esetében, ezeket az operációs rendszer szolgáltatja az alkalmazásnak, a felhasználó által beállított alapértelmezett egérviselkedési várakozások mellett.</p><h2 id="javafx-eredetu-esemenyek" tabindex="-1"><a class="header-anchor" href="#javafx-eredetu-esemenyek" aria-hidden="true">#</a> JavaFX-eredetű események</h2><p>A JavaFX képes saját események létrehozására és küldésére is. Ezeknek az eseményeknek három típusa van:</p><ul><li>Action Events</li><li>Worker Events</li><li>Edit, Modification and Sorting Events</li></ul><p>Minden típus lehetővé teszi a JavaFX számára, hogy funkcionalitást helyezzen a felhasználói felület fölé.</p><h3 id="action-events" tabindex="-1"><a class="header-anchor" href="#action-events" aria-hidden="true">#</a> Action Events</h3><p>A <code>Action Events</code> eseményeket úgy tervezték, hogy több bemeneti típusra is kiterjedjenek, és egyetlen végrehajtható kódot határozzanak meg, amelyet egy adott felhasználói művelet esetén használnak. Az olyan vezérlőelemek, mint a <code>TextField</code> és a gombok rendelkeznek <code>Action Event</code>-el.</p><p>Ez a funkcionalitás rétegezést biztosít a felhasználói felület felett egy olyan módon, amely több felhasználói bevitelt is felölel. Az akció a JavaFX rendszer nézőpontjából nézve egyfajta megerősítő felhasználói művelet. Példák erre:</p><ol><li>Gombra kattintás</li><li>Az Enter lenyomása, amikor a gomb van fókuszban</li><li>Az Enter lenyomása egy TextField-ben</li><li>Egy kapcsológomb felfegyverezése vagy lefegyverezése (billentyűzettel vagy egérrel)</li><li>Menügombra kattintás (vagy Enter leütése)</li></ol><p>Mindezekben az esetekben a <strong>JavaFX</strong> támogatja a következetes felhasználói elvárásokon alapuló műveletek végrehajtását, például egy űrlap elküldését az űrlap utolsó szövegmezőjének Enter billentyűjének megnyomásával, ahelyett, hogy a gombra kellene kattintani. Ily módon ugyanazt a végrehajtható kódot - ugyanazt az <code>EventHandler</code>-t - használhatjuk a szövegmező és a <code>Submit</code> gomb kezelésére is az alkalmazásunkban.</p><h4 id="target-kivalasztasa" tabindex="-1"><a class="header-anchor" href="#target-kivalasztasa" aria-hidden="true">#</a> Target kiválasztása</h4><p>Az <code>Action Event</code>-ek arra vannak tervezve, hogy több bemeneti módszert is felöleljenek. Ezért az <code>Action Event</code>-ek célpontja az a csomópont, amelyre kattintottak vagy amely fókuszban van (<em>billentyűesemény esetén</em>).</p><h4 id="action-event-tipusok" tabindex="-1"><a class="header-anchor" href="#action-event-tipusok" aria-hidden="true">#</a> Action Event típusok</h4><p>Az <code>ActionEvent</code> osztálynak csak egy <code>EventType</code>-ja van, amely <code>ACTION</code> néven található. Amikor egy felhasználó egy gombra kattint, az nincs több állapotban. Egy dolgot csinál - elkötelezi magát egy művelet mellett.</p><h4 id="hogyan-hasznaljuk-az-action-eventeket" tabindex="-1"><a class="header-anchor" href="#hogyan-hasznaljuk-az-action-eventeket" aria-hidden="true">#</a> Hogyan használjuk az Action Eventeket</h4><p>Leggyakrabban az <code>Action Event</code>-kezelőket a <code>setOnAction()</code> kényelmes módszerrel adják hozzá. Ritkán van szükség több funkcionalitásra, ezért más eseménykezelők felülírása kevésbé fontos.</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code>textField<span class="token punctuation">.</span><span class="token function">setOnAction</span><span class="token punctuation">(</span>event <span class="token operator">-&gt;</span> <span class="token punctuation">{</span>
    <span class="token comment">//eevnt action defined with lambda</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Mint bármely eseménnyel, azokat beállíthatjuk az <code>addEventHandler()</code> és <code>addEventFilter()</code> metódusokkal.</p><p>Végül ezeket az <strong>FXML</strong>-ben a következő szintaxissal lehet definiálni:</p><div class="language-xml line-numbers-mode" data-ext="xml"><pre class="language-xml"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>TextField</span> <span class="token attr-name">onAction</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>#handleTextCommit<span class="token punctuation">&quot;</span></span> <span class="token attr-name"><span class="token namespace">fx:</span>id</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>textField<span class="token punctuation">&quot;</span></span><span class="token punctuation">/&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>A <strong>&quot;#&quot;</strong> szimbólum a <code>FXMLLoader</code>-nek azt az utasítást adja, hogy injektálja a <code>handleTextCommit(ActionEvent event)</code> metódust a <code>TextField</code> <code>onAction</code> tulajdonságába. A <code>handleTextCommit()</code> metódusnak jelen kell lennie a vezérlőben (a megfelelő <code>ActionEvent</code> argumentummal), különben betöltési kivétel (<em>load exception</em>) keletkezik.</p><h4 id="viselkedese" tabindex="-1"><a class="header-anchor" href="#viselkedese" aria-hidden="true">#</a> Viselkedése</h4><p>Fontos megérteni, hogy a műveleti esemény és az azt kiváltó bemeneti esemény nem zárják ki egymást. Tehát, amikor egy műveleti esemény bekövetkezik, a hozzá tartozó billentyűleütés, egérkattintás vagy érintés is bekövetkezik.</p><p>Bár nem mindennapi, hogy a jelenet magasabb csomópontjain az <code>addEventFilter()</code> segítségével szűrjük az eseményeket, ez mégis lehetséges, ugyanúgy, mint bármely más típusú esemény esetén.</p><h3 id="worker-state-events" tabindex="-1"><a class="header-anchor" href="#worker-state-events" aria-hidden="true">#</a> Worker State Events</h3><p>Hosszabb-rövidebb ideig futó feladatok könnyen kiszervezhetők olyan munkavégzőknek, mint a &quot;Task&quot;-ok vagy &quot;Service&quot;-ek. Hasznos lehet eseményeket kiváltani ezek előrehaladása során.</p><h3 id="edit-modification-and-sorting-events" tabindex="-1"><a class="header-anchor" href="#edit-modification-and-sorting-events" aria-hidden="true">#</a> Edit, Modification and Sorting Events</h3><p>Ezek az események számos felhasználási területet ölelnek fel, de mindannyian olyan összetett felhasználói felület elemeinek frissítéséért felelősek, amelyek nem valósíthatók meg tulajdonságkötéssel.</p><h2 id="konkluzio" tabindex="-1"><a class="header-anchor" href="#konkluzio" aria-hidden="true">#</a> Konklúzió</h2><p>Az események a JavaFX egyik alapvető részét képezik, és szinte minden olyan kód, amely a felhasználói felület frissítéséhez szükséges, az események és tulajdonságkötések segítségével valósítható meg.</p><p>Az események közvetítik a felhasználó és az alkalmazás közötti interakciókat. Például, ha egy <code>TextField</code> szövegét egy <code>FilteredList</code>-hez szeretnénk kötni, akkor az események segítségével vezérelhetjük a felhasználói interakciók által kiváltott frissítéseket.</p><p>Még akkor is, ha a felhasználó csak gépel, az események használata a változásfigyelőkhöz képest előnyös lehet, mert az események általában stabilabbak, és kevésbé valószínű, hogy egyetlen billentyűleütés esetén több változás következik be.</p><p>Az események emellett kiválóan alkalmazhatók összetett háttérfeladatok és a felhasználói felület közötti kommunikációra. A függő felhasználói felületek elkerülése érdekében érdemes feladatokat használni és azokhoz eseményeket kapcsolni.</p>`,141),r=[d];function k(c,z){return a(),n("div",null,r)}const g=e(i,[["render",k],["__file","lesson3e.html.vue"]]);export{g as default};
